  'ganzhou/house': ('Nhà thổ lâu Khách Gia', 'Văn hóa Khách Gia đã tồn tại hàng thế kỷ trong những ngôi nhà pháo đài hình tròn độc đáo.'),
  'ganzhou/pavilion': ('Đình Úc Cô', 'Từng được các thi sĩ thời Tống ca ngợi, ngôi đình này có tầm nhìn bao quát nơi giao thoa của các dòng sông.'),
  'ganzhou/star': ('Vạn lý Trường chinh', 'Cuộc Vạn lý Trường chinh của Hồng quân Trung Quốc đã bắt đầu từ chính thành phố này.'),
  'putian/shrine': ('Đền thờ Mẹ Ma Tổ', 'Nữ thần Ma Tổ, vị thần bảo hộ ngư dân, đã sinh ra tại đây và ngôi đền thờ chính của bà tọa lạc trên đảo Mi Châu.'),
  'putian/lychee': ('Vườn vải', 'Những gốc vải nghìn năm tuổi đã mang lại cho thành phố này danh xưng \'vùng đất của vải thiều\'.'),
  'putian/shoe': ('Thủ phủ giày dép', 'Một phần lớn sản lượng giày thể thao trên thế giới được sản xuất tại các xưởng ở đây.'),
  'putian/wave': ('Đảo Mi Châu', 'Hòn đảo này nổi tiếng với những bãi biển thơ mộng và các lễ hội đền chùa đặc sắc, có thể di chuyển đến bằng phà.'),
  'mudanjiang/snow': ('Làng Tuyết', 'Ngôi làng cổ tích này được bao phủ bởi những lớp tuyết dày trắng xóa, tỏa sáng rực rỡ vào mùa đông.'),
  'mudanjiang/lake': ('Hồ Kính Bạc', 'Đây là một hồ nước chắn ngang do núi lửa tạo thành, nơi có thác Điếu Thủy Lâu vẫn đổ nước ngay cả trong mùa đông giá rét.'),
  'mudanjiang/tiger': ('Công viên Hổ Siberia', 'Đây là một trong những khu bảo tồn hổ Siberia lớn nhất trên thế giới.'),
  'mudanjiang/ski': ('Mùa trượt tuyết', 'Mùa đông dài đầy tuyết đã đưa khu vực này trở thành điểm đến không thể bỏ qua của những người đam mê trượt tuyết.'),
  'changzhou/dino': ('Công viên Khủng long', 'Công viên chủ đề về khủng long nổi tiếng nhất Trung Quốc này là biểu tượng du lịch gia đình của thành phố.'),
  'changzhou/pagoda': ('Chùa Thiên Ninh', 'Với chiều cao 153 mét, đây là ngôi chùa cao nhất thế giới nằm ngay trung tâm thành phố.'),
  'changzhou/comb': ('Nghề làm lược', 'Những chiếc lược Thường Châu với lịch sử ngàn năm từng là món quà quý giá được dâng lên cung đình.'),
  'changzhou/canal': ('Đại Vận Hà', 'Dọc theo bờ kênh là nơi lý tưởng để tản bộ, ngắm nhìn những khu phố cổ và ánh đèn đêm lung linh.'),
  'shaoxing/wine': ('Rượu Thiệu Hưng', 'Loại rượu gạo vàng trứ danh dùng trong ẩm thực Trung Hoa này đã được ủ tại đây hàng ngàn năm qua.'),
  'shaoxing/bridge': ('Cầu đá cổ', 'Thiệu Hưng với hệ thống kênh rạch chằng chịt vẫn còn lưu giữ hàng trăm cây cầu đá hình vòm cổ kính.'),
  'shaoxing/pen': ('Cái nôi thư pháp', 'Lan Đình của thư pháp gia Vương Hy Chi được coi là thánh địa của nghệ thuật thư pháp.'),
  'shaoxing/boat': ('Thuyền Ô Bồng', 'Những chiếc thuyền Ô Bồng được chèo bằng chân là phương tiện di chuyển cổ điển trên các con kênh ở đây.'),
  'bengbu/shell': ('Cảng Ngọc Trai', 'Tên gọi của thành phố có nghĩa là \'bến hàu\', nơi từng nổi tiếng với những viên ngọc trai quý giá từ sông Hoài.'),
  'bengbu/train': ('Cửa ngõ đường sắt', 'Thành phố này phát triển mạnh mẽ nhờ vị trí là điểm giao cắt quan trọng của tuyến đường sắt Bắc - Nam qua sông Hoài.'),
  'bengbu/river': ('Sông Hoài', 'Đây là dòng sông đóng vai trò là ranh giới tự nhiên phân chia văn hóa miền Bắc và miền Nam Trung Quốc.'),
  'bengbu/blossom': ('Lễ hội hoa xuân', 'Mỗi độ xuân về, các công viên ven sông lại rực rỡ sắc hoa trong những lễ hội truyền thống.'),
  'jiujiang/mountain': ('Lư Sơn', 'Được UNESCO công nhận là di sản thế giới, những đỉnh núi mờ sương của Lư Sơn đã khơi nguồn cảm hứng cho biết bao thi nhân và họa sĩ.'),
  'jiujiang/tea': ('Trà Vân Vụ', 'Loại trà Vân Vụ trồng trên sườn núi Lư Sơn được mệnh danh là một trong những loại trà tinh tế nhất Trung Quốc.'),
  'jiujiang/lake': ('Hồ Bà Dương', 'Là hồ nước ngọt lớn nhất Trung Quốc, đây là nơi trú đông của hàng ngàn con sếu mỗi năm.'),
  'jiujiang/scroll': ('Thành phố thi ca', 'Cửa ngõ ven sông này chính là nơi lưu giữ những vần thơ bất hủ của các đại thi hào như Bạch Cư Dị và Tô Thức.'),
  'quanzhou/ship': ('Con đường tơ lụa trên biển', 'Từng được Marco Polo gọi là \'Zayton\', đây là cảng biển lớn nhất thế giới thời trung cổ và hiện là di sản UNESCO.'),
  'quanzhou/mosque': ('Thanh Tịnh Tự', 'Được xây dựng từ năm 1009, đây là một trong những thánh đường Hồi giáo cổ xưa nhất tại Trung Quốc.'),
  'quanzhou/puppet': ('Múa rối dây', 'Nghệ thuật múa rối dây Tuyền Châu là một truyền thống sân khấu có lịch sử lâu đời hàng ngàn năm.'),
  'quanzhou/tea': ('Trà Thiết Quan Âm', 'Loại trà ô long đến từ vùng An Khê lân cận này là danh trà Thiết Quan Âm nổi tiếng thế giới.'),
  'shanghai/pearl': ('Tháp Minh Châu Phương Đông', 'Với những quả cầu màu hồng vươn cao bên dòng Hoàng Phố, tòa tháp này là biểu tượng cho sự hiện đại của Thượng Hải.'),
  'shanghai/bund': ('Bến Thượng Hải', 'Những tòa nhà lịch sử dọc bờ sông phản chiếu vẻ đẹp huy hoàng của Thượng Hải thời xưa.'),
  'shanghai/garden': ('Dự Viên', 'Một khu vườn cổ điển thời nhà Minh với những hòn non bộ và hồ nước, tạo nên ốc đảo yên bình giữa lòng thành phố.'),
  'shanghai/xlb': ('Tiểu long bao', 'Những chiếc bánh bao hấp chứa đầy nước dùng nóng hổi là món điểm tâm tinh túy nhất của Thượng Hải.'),
  'hangzhou/lake': ('Tây Hồ', 'Với những hàng liễu, đảo nhỏ và cầu vòm, đây là hồ nước được ca ngợi nhiều nhất trong thi ca Trung Hoa.'),
  'hangzhou/tea': ('Trà Long Tỉnh', 'Được trồng trên các sườn đồi quanh hồ, loại trà xanh \'Giếng Rồng\' này là danh trà nổi tiếng nhất Trung Quốc.'),
  'hangzhou/temple': ('Chùa Linh Ẩn', 'Ngôi chùa 1.700 năm tuổi này nổi tiếng với các tác phẩm chạm khắc đá tinh xảo và tượng Phật khổng lồ.'),
  'hangzhou/silk': ('Phố lụa Hàng Châu', 'Lụa Hàng Châu đã được dệt suốt hàng ngàn năm, tạo nên sự thịnh vượng cho điểm cuối phía đông của Con đường Tơ lụa.'),
  'chongqing/hongya': ('Hồng Nhai Động', 'Tổ hợp nhà sàn rực rỡ bám vào vách đá, tỏa sáng như trong truyện cổ tích bên bờ sông khi đêm về.'),
  'chongqing/hotpot': ('Lẩu Trùng Khánh', 'Với nước dùng sôi sùng sục đầy ớt và gia vị tê cay, lẩu chính là linh hồn nồng nhiệt của thành phố núi này.'),
  'chongqing/monorail': ('Đường sắt trên cao Trùng Khánh', 'Tuyến đường sắt chạy xuyên qua tòa nhà là hình ảnh biểu tượng độc đáo của thành phố xây dựng trên địa hình đồi núi.'),
  'chongqing/river': ('Tam Hiệp Trường Giang', 'Các chuyến du thuyền Tam Hiệp khởi hành từ cảng này, nơi thành phố vươn mình tại điểm giao thoa của hai dòng sông.'),
  'dalian/square': ('Quảng trường Tinh Hải', 'Quảng trường thành phố lớn nhất châu Á này là nơi diễn ra nhiều lễ hội và chương trình biểu diễn dọc bờ biển.'),
  'dalian/beach': ('Bãi biển Đại Liên', 'Với những vịnh đá và mùa hè mát mẻ, Đại Liên là khu nghỉ dưỡng ven biển được yêu thích nhất ở miền Bắc.'),
  'dalian/football': ('Thành phố bóng đá', 'Được mệnh danh là \'cái nôi bóng đá\' của Trung Quốc, đây là nơi ra đời của những câu lạc bộ giàu thành tích nhất cả nước.'),
  'dalian/seafood': ('Hải sản Đại Liên', 'Các loại sò điệp, tôm và nhím biển từ vùng biển Hoàng Hải lạnh giá luôn là món ngon đặc sắc trên bàn ăn của thành phố.'),
  'shenyang/palace': ('Thẩm Dương Cố Cung', 'Đây là cung điện đầu tiên của nhà Thanh, được xem như người anh em nhỏ hơn của Tử Cấm Thành ở Bắc Kinh.'),
  'shenyang/tomb': ('Lăng mộ nhà Thanh', 'Các khu lăng mộ phía Đông và phía Bắc bao quanh thành phố là những công trình tưởng niệm hoành tráng của các vị hoàng đế khai quốc.'),
  'shenyang/factory': ('Cái nôi công nghiệp', 'Nền công nghiệp nặng của Trung Quốc khởi nguồn từ đây, với những nhà máy khổng lồ giúp thành phố được mệnh danh là \'vùng Ruhr của phương Đông\'.'),
  'shenyang/dumpling': ('Sủi cảo Lão Biên', 'Món sủi cảo hấp Lão Biên với lịch sử hơn 200 năm là đặc sản trứ danh trên bàn tiệc phương Bắc.'),
  'hefei/judge': ('Bao Công Từ', 'Là quê hương của vị quan thanh liêm Bao Chửng, ngôi đền này chính là biểu tượng cho sự chính trực.'),
  'hefei/science': ('Thành phố Khoa học', 'Đây là trung tâm công nghệ quy tụ nhiều trường đại học và phòng thí nghiệm hàng đầu của Trung Quốc.'),
  'hefei/lake': ('Hồ Sào', 'Một trong năm hồ nước ngọt lớn nhất Trung Quốc, nổi tiếng với đặc sản cá trắng và cua.'),
  'hefei/cake': ('Bánh mè Lư Châu', 'Món bánh mè nhân ngọt này là thức quà truyền thống lâu đời của vùng đất Lư Châu xưa.'),
  'foshan/wingchun': ('Vịnh Xuân Quyền', 'Đây là cái nôi của võ thuật Vịnh Xuân, nơi khởi nguồn của những huyền thoại như Diệp Vấn và Lý Tiểu Long.'),
  'foshan/lion': ('Múa lân', 'Được mệnh danh là thủ phủ của múa lân phương Nam, nơi những chú lân rực rỡ sắc màu nhảy múa điêu luyện trên các cột cao.'),
  'foshan/ceramic': ('Gốm Thạch Loan', 'Những lò gốm nghìn năm tuổi vẫn tiếp tục cho ra đời các tác phẩm tượng gốm Thạch Loan đầy sống động.'),
  'foshan/opera': ('Kịch Quảng Đông', 'Loại hình nghệ thuật sân khấu được yêu thích nhất miền Nam Trung Quốc đã phát triển rực rỡ trên mảnh đất này.'),
  'guiyang/pavilion': ('Giáp Tú Các', 'Tòa lầu ba tầng nằm trên sông Nam Minh này đã trở thành biểu tượng của thành phố suốt 400 năm qua.'),
  'guiyang/sourfish': ('Cá nấu canh chua', 'Món cá nấu trong nước dùng cà chua lên men có vị chua thanh đặc trưng là món ăn tiêu biểu của Quý Châu.'),
  'guiyang/waterfall': ('Thác Hoàng Quả Thụ', 'Một trong những thác nước lớn nhất châu Á đổ xuống ầm ầm, tạo nên những dải cầu vồng tuyệt đẹp.'),
  'guiyang/miao': ('Văn hóa người Miêu', 'Những lễ hội và nghề thêu thùa của người dân tộc Miêu với trang phục đội vương miện bạc đã làm bừng sáng các bản làng vùng núi.'),
  'changchun/film': ('Thành phố Điện ảnh', 'Nơi đây được mệnh danh là \'Hollywood của phương Đông\', cái nôi khai sinh ra nền điện ảnh Trung Quốc.'),
  'changchun/car': ('Thành phố Ô tô', 'Đây là thủ phủ ô tô của cả nước, nơi những chiếc xe hơi đầu tiên do Trung Quốc tự sản xuất đã ra đời.'),
  'changchun/palace': ('Ngụy Mãn Hoàng cung', 'Nơi ở của vị hoàng đế cuối cùng là nhân chứng thầm lặng cho một giai đoạn lịch sử đầy biến động.'),
  'changchun/snow': ('Tuyết mùa đông', 'Suốt mùa đông dài trắng xóa, thành phố bừng sáng với những tác phẩm điêu khắc băng và các đường trượt tuyết.'),
  'xining/lake': ('Hồ Thanh Hải', 'Hồ nước mặn lớn nhất Trung Quốc nổi tiếng với những cánh đồng hoa cải vàng rực rỡ bao quanh vào mùa hè.'),
  'xining/monastery': ('Tu viện Kumbum', 'Một trong sáu tu viện lớn nhất của Phật giáo Tây Tạng, nổi danh với những tác phẩm điêu khắc từ bơ bò yak.'),
  'xining/flower': ('Hoa cải dầu', 'Vào tháng Bảy, cả cao nguyên như được phủ một tấm thảm vàng óng của những cánh đồng hoa cải trải dài đến tận chân trời.'),
  'xining/lamb': ('Thịt bò yak và thịt cừu', 'Mì kéo tay và thịt cừu xiên nướng mang đậm phong vị ẩm thực Hồi giáo và Tây Tạng là đặc sản của vùng cao nguyên này.'),
  'guilin/karst': ('Núi đá vôi sông Ly', 'Những ngọn núi đá vôi nhô lên từ làn sương mù chính là khung cảnh được in trên tờ tiền 20 nhân dân tệ.'),
  'guilin/elephant': ('Núi Vòi Voi', 'Tảng đá có hình dáng như chú voi đang cúi vòi xuống dòng sông là biểu tượng thân thuộc của thành phố.'),
  'guilin/terrace': ('Ruộng bậc thang Long Tích', 'Những thửa ruộng bậc thang \'Sống lưng rồng\' uốn lượn trên sườn núi là minh chứng cho công sức lao động qua hàng thế kỷ.'),
  'guilin/osmanthus': ('Hoa mộc tê', 'Tên gọi của thành phố có nghĩa là \'rừng hoa mộc\', nơi vào mùa thu tràn ngập hương thơm ngọt ngào của loài hoa này.'),
  'wenzhou/merchant': ('Tinh thần thương nhân', 'Được mệnh danh là \'người Do Thái của Trung Quốc\', các doanh nhân Ôn Châu đã xây dựng mạng lưới kinh doanh trên khắp thế giới.'),
  'wenzhou/shoe': ('Giày dép và đồ da', 'Một phần lớn sản lượng giày da trên thế giới được sản xuất từ thành phố công nghiệp này.'),
  'wenzhou/mountain': ('Núi Nhạn Đãng', 'Nổi tiếng với những thác nước và đỉnh núi hiểm trở, nơi đây được ca ngợi là \'đệ nhất danh sơn ven biển\'.'),
  'wenzhou/seafood': ('Hải sản', 'Mực, sò điệp và các loại cá từ biển Hoa Đông là nguyên liệu chính trong các bữa ăn của người dân địa phương.'),
  'tangshan/memorial': ('Đài tưởng niệm động đất', 'Công viên tưởng niệm trận động đất lớn năm 1976 là biểu tượng cho sự hồi sinh mạnh mẽ của thành phố.'),
  'tangshan/coal': ('Than đá và thép', 'Nơi đây từng là cái nôi công nghiệp với mỏ than và tuyến đường sắt hiện đại đầu tiên của Trung Quốc.'),
  'tangshan/ceramic': ('Gốm sứ Đường Sơn', 'Được mệnh danh là \'thành phố gốm sứ phương Bắc\', các sản phẩm sứ xương tại đây luôn nổi tiếng với vẻ đẹp tinh tế.'),
  'tangshan/lake': ('Công viên Nam Hồ', 'Khu công viên hồ nước này vốn được cải tạo từ một hố mỏ cũ, nay đã trở thành lá phổi xanh của thành phố.'),
  'anshan/steel': ('Thành phố thép', 'Đây là nơi đặt nhà máy thép lớn nhất Trung Quốc, được mệnh danh là \'thủ phủ thép\' của cả nước.'),
  'anshan/jade': ('Ngọc Tú Nham', 'Thành phố này là vùng đất ngọc của Trung Quốc, nơi lưu giữ tác phẩm điêu khắc bằng ngọc lớn nhất thế giới.'),
  'anshan/mountain': ('Núi Thiên Sơn', 'Với những ngôi chùa cổ và vách đá hùng vĩ, \'Thiên Sơn\' được coi là ngọn núi linh thiêng bậc nhất phương Bắc.'),
  'anshan/spring': ('Suối nước nóng Đường Cương Tử', 'Suối nước nóng này đã có lịch sử chữa bệnh hàng ngàn năm và từng là nơi nghỉ dưỡng của các bậc hoàng đế.'),
  'linyi/market': ('Chợ bán buôn Lâm Nghi', 'Đây là trung tâm bán buôn lớn nhất miền Bắc Trung Quốc, chuyên phân phối hàng hóa đi khắp cả nước.'),
  'linyi/brush': ('Quê hương thư pháp', 'Lâm Nghi là quê hương của \'Thư thánh\' Vương Hy Chi, được mệnh danh là vùng đất của mực và bút.'),
  'linyi/mountain': ('Núi Mông Sơn', 'Là ngọn núi cao thứ hai ở Sơn Đông, nơi đây được ví như một \'trạm oxy\' với không khí trong lành và những thác nước tuyệt đẹp.'),
  'linyi/pancake': ('Bánh kếp Nghi Mông', 'Loại bánh kếp mỏng làm từ ngô này là món ăn truyền thống lâu đời của người dân vùng núi Nghi Mông.'),
  'cangzhou/lion': ('Sư tử sắt Thương Châu', 'Bức tượng sư tử bằng sắt khổng lồ có niên đại 1.100 năm này là biểu tượng đầy tự hào của thành phố.'),
  'cangzhou/martial': ('Võ thuật Thương Châu', 'Được mệnh danh là \'quê hương của võ thuật\', Thương Châu là cái nôi sản sinh ra nhiều bậc thầy và võ đường danh tiếng.'),
  'cangzhou/canal': ('Đại Vận Hà', 'Kênh đào Đại Vận Hà Bắc Kinh - Hàng Châu chảy qua thành phố, nơi vẫn còn lưu giữ những bến tàu cổ kính.'),
  'cangzhou/jujube': ('Táo tàu vàng', 'Loại táo tàu \'tơ vàng\' với lớp vỏ mỏng và vị ngọt thanh được mệnh danh là vua của các loại trái cây sấy khô.'),
  'nantong/textile': ('Thành phố Dệt may', 'Được mệnh danh là thủ phủ dệt may của Trung Quốc, các sản phẩm vải bông tại đây đã vươn ra thị trường toàn cầu.'),
  'nantong/mountain': ('Núi Lang', 'Nằm ngay cửa sông Dương Tử, ngọn núi linh thiêng với năm đỉnh này là điểm đến hành hương và ngắm cảnh nổi tiếng.'),
  'nantong/kite': ('Diều sáo', 'Những chiếc diều sáo \'banyao\' với âm thanh ngân vang là một loại hình thủ công truyền thống lâu đời của thành phố.'),
  'nantong/school': ('Cái nôi giáo dục', 'Nhà công nghiệp Trương Kiên đã thành lập những ngôi trường hiện đại và bảo tàng đầu tiên của Trung Quốc tại đây.'),
  'taizhou/opera': ('Mai Lan Phương', 'Đây là quê hương của Mai Lan Phương, bậc thầy huyền thoại của nghệ thuật Kinh kịch.'),
  'taizhou/tea': ('Trà sáng', 'Thưởng thức trà sáng cùng các loại bánh bao hấp đã trở thành một nét văn hóa ẩm thực đặc trưng của người dân nơi đây.'),
  'taizhou/boat': ('Lễ hội đua thuyền Cần Đồng', 'Vào mùa xuân, lễ hội với hàng trăm tay chèo tham gia tranh tài đã mang lại sức sống mãnh liệt cho dòng sông.'),
  'taizhou/meatball': ('Thịt viên đầu sư tử', 'Món thịt viên mềm mại, thơm ngon này là một trong những đặc sản kinh điển của ẩm thực Hoài Dương.'),
  'jinhua/ham': ('Giăm bông Kim Hoa', 'Được chế biến theo phương pháp truyền thống hàng thế kỷ, đây là loại giăm bông nổi tiếng nhất tại Trung Quốc.'),
  'jinhua/film': ('Phim trường Hoành Điếm', 'Đây là phim trường ngoài trời lớn nhất thế giới, nơi ghi hình cho vô số bộ phim cổ trang nổi tiếng.'),
  'jinhua/cave': ('Động Song Long', 'Du khách sẽ được trải nghiệm cảm giác choáng ngợp khi đi thuyền qua cửa hang đá thấp để tiến vào hang động ngầm kỳ vĩ này.'),
  'jinhua/bridge': ('Cầu cổ', 'Những cây cầu đá vòm cùng các thị trấn ven sông mang đậm vẻ đẹp thanh tao của vùng Giang Nam.'),
  'wuhu/park': ('Công viên giải trí Phương Đặc', 'Là một trong những công viên giải trí lớn nhất Trung Quốc, nơi đây mang đến những ngày vui chơi đầy phấn khích cho cả gia đình.'),
  'wuhu/ironart': ('Tranh sắt', 'Những bức tranh sắt tinh xảo được rèn từ sắt uốn là một loại hình nghệ thuật thủ công có lịch sử 300 năm.'),
  'wuhu/rice': ('Cảng gạo', 'Nằm bên bờ sông Dương Tử, thành phố này từng là thị trường kinh doanh gạo lớn nhất Trung Quốc trong lịch sử.'),
  'wuhu/river': ('Cảng Dương Tử', 'Đây là một cảng sông sầm uất, đóng vai trò là cửa ngõ thông ra biển của tỉnh An Huy.'),
  'huangshan/peak': ('Hoàng Sơn', 'Với những đỉnh núi đá granite, biển mây bồng bềnh và những cây thông cổ thụ, đây là ngọn núi nổi tiếng nhất Trung Quốc.'),
  'huangshan/village': ('Thôn Hoành', 'Ngôi làng cổ với những bức tường trắng soi bóng bên dòng nước này đã được UNESCO công nhận là di sản thế giới, đẹp tựa như một bức tranh thủy mặc.'),
  'huangshan/tea': ('Trà Mao Phong', 'Được hái trên những sườn núi mờ sương, loại trà xanh với búp lá phủ lông tơ này là một trong mười loại danh trà nổi tiếng nhất Trung Quốc.'),
  'huangshan/ink': ('Mực và nghệ thuật Huy Châu', 'Mực Huy Châu, những ngôi nhà gỗ chạm khắc tinh xảo và thư pháp chính là kho tàng văn hóa quý giá của vùng đất này.'),
  'yichun/moon': ('Núi Minh Nguyệt', 'Ngọn núi \'Trăng Sáng\' này nổi tiếng với những suối nước nóng và tầm nhìn tuyệt đẹp từ cáp treo.'),
  'yichun/spring': ('Suối nước nóng', 'Những suối nước nóng giàu selen quý hiếm đã biến thành phố này thành trung tâm tắm khoáng hàng đầu Trung Quốc.'),
  'yichun/zen': ('Thiền tông', 'Những ngôi chùa cổ nằm sâu trong núi, nơi khởi nguồn của các tông phái Thiền tông Trung Hoa, mang đến cảm giác tĩnh tại trong tâm hồn.'),
  'yichun/rice': ('Đồng bằng Viên Hà', 'Vùng đồng bằng màu mỡ Viên Hà từ lâu đã được coi là vựa lúa của tỉnh Giang Tây.'),
  'zhangzhou/narcissus': ('Hoa thủy tiên', 'Đây là nơi trồng hoa thủy tiên nổi tiếng nhất Trung Quốc, loài hoa biểu tượng cho các dịp lễ hội mùa xuân.'),
  'zhangzhou/tulou': ('Thổ lâu Khách Gia', 'Những pháo đài bằng đất nện hình tròn khổng lồ này là di sản UNESCO, nơi cả một ngôi làng cùng sinh sống dưới một mái nhà.'),
  'zhangzhou/banana': ('Trái cây nhiệt đới', 'Những vườn chuối, nhãn và quýt giúp vùng đồng bằng ấm áp này luôn xanh tươi quanh năm.'),
  'zhangzhou/coast': ('Đảo Đông Sơn', 'Với những bãi biển vàng óng và các làng chài yên bình, hòn đảo này được ví như viên ngọc quý của vùng duyên hải phía Nam.'),
  'guangzhou/tower': ('Tháp Quảng Châu', 'Với biệt danh \'Tiểu Man Yêu\', tòa tháp cao chọc trời này rực rỡ sắc màu mỗi khi đêm về, trở thành biểu tượng của thành phố.'),
  'guangzhou/dimsum': ('Trà sáng', 'Thưởng thức dim sum trong những xửng tre nóng hổi cùng trà thơm là nét văn hóa ẩm thực đặc trưng và là linh hồn của người Quảng Đông.'),
  'guangzhou/academy': ('Từ đường dòng họ Trần', 'Nổi tiếng với các tác phẩm chạm khắc gỗ và phù điêu gốm sứ tinh xảo, đây là kiệt tác tiêu biểu cho nghệ thuật thủ công Quảng Đông.'),
  'guangzhou/flower': ('Thành phố Hoa', 'Với hoa nở quanh năm và các hội chợ hoa quy mô lớn mỗi dịp Tết, Quảng Châu được mệnh danh là \'Thành phố Hoa\'.'),
  'wuhan/crane': ('Hoàng Hạc Lâu', 'Tọa lạc bên bờ sông Dương Tử, tòa tháp nghìn năm tuổi này là nguồn cảm hứng cho nhiều bài thơ nổi tiếng nhất Trung Quốc.'),
  'wuhan/noodle': ('Mì khô nóng', 'Mì khô nóng trộn sốt mè là món ăn sáng không thể thiếu của người dân Vũ Hán.'),
  'wuhan/duckneck': ('Cổ vịt cay', 'Cổ vịt om cay là món ăn vặt khoái khẩu của người dân địa phương trong những buổi trò chuyện đêm khuya.'),
  'wuhan/university': ('Hoa anh đào Đại học Vũ Hán', 'Mùa hoa anh đào tại Đại học Vũ Hán thu hút hàng nghìn du khách ghé thăm mỗi độ xuân về.'),
  'tianjin/eye': ('Mắt Thiên Tân', 'Đây là vòng quay mặt trời được xây dựng ngay trên cầu, cho phép du khách ngắm nhìn toàn cảnh hai bên bờ sông.'),
  'tianjin/baozi': ('Bánh bao Cẩu Bất Lý', 'Món bánh bao nhân thịt hấp với lớp vỏ xếp nếp tinh tế này là đặc sản trứ danh có lịch sử 150 năm của Thiên Tân.'),
  'tianjin/crosstalk': ('Tướng thanh', 'Tướng thanh là loại hình hài kịch đối đáp hai người truyền thống của Thiên Tân, khởi nguồn từ các quán trà địa phương.'),
  'tianjin/architecture': ('Khu phố châu Âu', 'Những căn biệt thự mang phong cách châu Âu tại Ngũ Đại Đạo đã giúp Thiên Tân được ví như một \'bảo tàng kiến trúc\'.'),
  'xiamen/island': ('Đảo Cổ Lãng Tự', 'Với những con ngõ không bóng dáng xe cộ và các căn biệt thự cổ kính, hòn đảo được UNESCO công nhận này giống như một bảo tàng ngoài trời.'),
  'xiamen/piano': ('Đảo Dương cầm', 'Nhờ sở hữu số lượng đàn piano trên đầu người cao nhất cả nước, Cổ Lãng Tự còn được gọi là \'đảo dương cầm\'.'),
  'xiamen/egret': ('Cò trắng', 'Cò trắng là biểu tượng của thành phố, gợi nhắc về tên gọi cũ \'đảo cò\' của Hạ Môn.'),
  'xiamen/oyster': ('Trứng chiên hàu', 'Món trứng chiên hàu tươi giòn là ngôi sao ẩm thực trong các món ăn miền duyên hải.'),
  'harbin/ice': ('Lễ hội Băng đăng', 'Lễ hội mùa đông với những cung điện băng khổng lồ rực rỡ ánh đèn tại đây là sự kiện lớn nhất thế giới.'),
  'harbin/cathedral': ('Nhà thờ Thánh Sophia', 'Nhà thờ Chính thống giáo Nga với mái vòm hình củ hành này là biểu tượng cho di sản châu Âu của thành phố.'),
  'harbin/sausage': ('Xúc xích đỏ', 'Món xúc xích đỏ hun khói kiểu Nga là đặc sản có lịch sử trăm năm của thành phố này.'),
  'harbin/accordion': ('Thành phố Âm nhạc', 'Với bề dày di sản văn hóa Nga, Cáp Nhĩ Tân là nơi thành lập dàn nhạc giao hưởng đầu tiên của Trung Quốc.'),
  'fuzhou/alley': ('Tam Phường Thất Ngõ', 'Khu phố cổ với tường trắng ngói đen này là một bảo tàng sống động về kiến trúc thời Minh - Thanh.'),
  'fuzhou/banyan': ('Thành phố cây đa', 'Những cây đa cổ thụ khổng lồ tỏa bóng mát khắp các con phố khiến Phúc Châu được mệnh danh là \'thành phố cây đa\'.'),
  'fuzhou/hotspring': ('Suối nước nóng', 'Các mạch nước nóng tự nhiên chảy ngay trong lòng thành phố đã phục vụ các nhà tắm công cộng suốt cả ngàn năm qua.'),
  'fuzhou/soup': ('Phật nhảy tường', 'Được hầm từ hàng chục nguyên liệu quý, món súp xa xỉ này là kiệt tác đỉnh cao của ẩm thực Phúc Kiến.'),
  'dongguan/robot': ('Công xưởng thế giới', 'Với hệ thống nhà máy tự động hóa, Đông Quản là nơi sản xuất một phần lớn các thiết bị điện tử trên toàn cầu.'),
  'dongguan/basketball': ('Thành phố bóng rổ', 'Câu lạc bộ bóng rổ giàu thành tích nhất Trung Quốc đang thi đấu tại \'thành phố bóng rổ\' này.'),
  'dongguan/keyuan': ('Khả Viên', 'Đây là một trong bốn khu vườn cổ điển nổi tiếng nhất Quảng Đông, nổi tiếng với những hồ nước và đình đài tuyệt đẹp.'),
  'dongguan/cannon': ('Pháo đài Hổ Môn', 'Pháo đài Hổ Môn là nơi khởi đầu của Chiến tranh Nha phiến và cũng là địa điểm ghi dấu sự kiện tiêu hủy nha phiến năm xưa.'),
  'lanzhou/beefnoodle': ('Mì bò Lan Châu', 'Với nước dùng bò trong vắt và sợi mì kéo tay đặc trưng, Lan Châu được coi là thủ phủ mì sợi của Trung Quốc.'),
  'lanzhou/waterwheel': ('Guồng nước', 'Những chiếc guồng nước khổng lồ bên bờ sông Hoàng Hà là biểu tượng cho kỹ thuật tưới tiêu có từ hàng thế kỷ trước.'),
  'lanzhou/statue': ('Tượng Mẹ Hoàng Hà', 'Bức tượng mẹ và con bên bờ sông khắc họa hình ảnh dòng sông đã nuôi dưỡng nền văn minh Trung Hoa.'),
  'lanzhou/raft': ('Bè da cừu', 'Những chiếc bè truyền thống làm từ da cừu thổi phồng vẫn đang trôi trên dòng sông Hoàng Hà cho đến tận ngày nay.'),
  'urumqi/bazaar': ('Đại chợ Tân Cương', 'Với những tòa tháp cao vút và các quầy gia vị sặc sỡ, khu chợ này mang đậm dấu ấn màu sắc của Con đường Tơ lụa.'),
  'urumqi/tianshan': ('Thiên Trì', 'Nằm dưới những đỉnh núi tuyết của dãy Thiên Sơn, hồ Thiên Trì được bao quanh bởi những cánh rừng vân sam xanh mướt.'),
  'urumqi/kebab': ('Thịt cừu xiên nướng', 'Những xiên thịt cừu tẩm gia vị nướng trên than hồng là món ăn không thể thiếu trong bữa cơm của người Duy Ngô Nhĩ.'),
  'urumqi/dance': ('Điệu múa Duy Ngô Nhĩ', 'Những điệu múa xoay người uyển chuyển của người Duy Ngô Nhĩ hòa cùng tiếng trống và đàn rawap luôn làm bừng sáng mọi lễ hội.'),
  'haikou/coconut': ('Thành phố Dừa', 'Những hàng dừa rợp bóng dọc các con phố đã mang lại cho Hải Khẩu biệt danh \'thành phố dừa\'.'),
  'haikou/arcade': ('Phố cổ Kỵ Lâu', 'Những tòa nhà \'kỵ lâu\' với lối kiến trúc hành lang có mái che tạo nên các con phố đi bộ râm mát đặc trưng của phương Nam.'),
  'haikou/crater': ('Miệng núi lửa', 'Các miệng núi lửa đã tắt tạo thành một công viên địa chất xanh mát nằm ngay rìa thành phố.'),
  'haikou/turtle': ('Biển nhiệt đới', 'Làn nước trong xanh ấm áp cùng những rạn san hô đã biến vùng biển nơi đây thành ngôi nhà của loài rùa biển.'),
  'luoyang/grotto': ('Hang đá Long Môn', 'Hàng chục ngàn bức tượng Phật được chạm khắc tinh xảo trên vách đá tạo nên một kho tàng nghệ thuật được UNESCO công nhận.'),
  'luoyang/peony': ('Thủ phủ hoa mẫu đơn', 'Hàng ngàn đóa mẫu đơn đua nhau khoe sắc mỗi độ tháng Tư đã biến Lạc Dương thành \'thủ phủ hoa mẫu đơn\'.'),
  'luoyang/whitehorse': ('Chùa Bạch Mã', 'Được xây dựng từ năm 68 sau Công nguyên, ngôi chùa này được coi là tu viện Phật giáo đầu tiên của Trung Quốc.'),
  'luoyang/capital': ('Cố đô Lạc Dương', 'Từng là kinh đô của mười ba triều đại, Lạc Dương được coi là một trong những cái nôi của nền văn minh Trung Hoa.'),
  'shantou/gongfutea': ('Trà đạo Triều Sán', 'Được pha chế cầu kỳ trong những chén nhỏ, trà đạo Triều Sán là một nghệ thuật hiếu khách đặc sắc.'),
  'shantou/beefpot': ('Lẩu bò Triều Sán', 'Món lẩu bò Triều Sán nổi tiếng với những lát thịt bò tươi ngon được nhúng chín chỉ trong vài giây.'),
  'shantou/opera': ('Kịch Triều Châu', 'Loại hình kịch Triều Châu với lịch sử 600 năm nổi tiếng nhờ những giai điệu tinh tế và trang phục thêu tay cầu kỳ.'),
  'shantou/harbor': ('Thành phố cảng Sán Đầu', 'Là quê hương của nhiều người Hoa hải ngoại, cảng biển này từng là cửa ngõ giao thương hàng hải lâu đời.'),
  'baoding/mansion': ('Phủ Tổng đốc Trực Lệ', 'Đây là cơ quan hành chính cấp tỉnh được bảo tồn nguyên vẹn nhất từ thời nhà Thanh.'),
  'baoding/donkeyburger': ('Bánh kẹp thịt lừa', 'Thịt lừa tẩm ướp gia vị kẹp trong lớp vỏ bánh giòn tan là món ăn đường phố đặc trưng của vùng này.'),
  'baoding/balls': ('Bóng tập dưỡng sinh', 'Việc xoay những quả cầu kim loại trong lòng bàn tay là một phương pháp tập luyện truyền thống có từ hàng trăm năm nay.'),
  'baoding/reeds': ('Đầm lầy Bạch Dương Điến', 'Vùng đất ngập nước lớn nhất miền Bắc này là thiên đường của các loài chim với những cánh đồng lau sậy và hoa sen bát ngát.'),
  'jilin/rime': ('Băng sương Cát Lâm', 'Hiện tượng băng sương phủ trắng xóa trên những hàng cây bên sông Tùng Hoa là một trong bốn kỳ quan thiên nhiên của Trung Quốc.'),
  'jilin/snowboard': ('Khu nghỉ dưỡng trượt tuyết', 'Với lớp tuyết dày và mùa đông kéo dài, thành phố này là một trong những điểm trượt tuyết hàng đầu ở miền Bắc.'),
  'jilin/meteorite': ('Bảo tàng Thiên thạch', 'Nơi đây trưng bày mảnh thiên thạch đá lớn nhất thế giới, rơi xuống trái đất vào năm 1976.'),
  'jilin/skate': ('Sông Tùng Hoa đóng băng', 'Vào mùa đông, dòng sông Tùng Hoa đóng băng trở thành một sân băng khổng lồ thu hút người dân đến trượt băng và dạo chơi.'),
  'ordos/khan': ('Lăng mộ Thành Cát Tư Hãn', 'Ngôi lăng mộ tráng lệ tôn vinh vị anh hùng thảo nguyên Thành Cát Tư Hãn là trái tim của văn hóa Mông Cổ.'),
  'ordos/cashmere': ('Len Cashmere', 'Sản phẩm len dệt từ lông dê Ordos đã đưa tên tuổi thành phố này vươn tầm thế giới trong ngành dệt may.'),
  'ordos/sanddune': ('Sa mạc Hưởng Sa Loan', 'Những cồn cát khổng lồ phát ra âm thanh khi bạn trượt xuống là điểm dừng chân thú vị nhất trên sa mạc Kubuqi.'),
  'ordos/yurt': ('Lều Yurt Mông Cổ', 'Những chiếc lều nỉ trắng dựng trên thảo nguyên bao la là biểu tượng cho cuộc sống du mục.'),
  'jining/confucius': ('Đền thờ Khổng Tử', 'Nằm ở Khúc Phụ gần đó, quần thể đền thờ, dinh thự và mộ phần của Khổng Tử đã được UNESCO công nhận là di sản thế giới.'),
  'jining/barge': ('Đại Vận Hà', 'Từng là một cảng thị sầm uất trên tuyến kênh đào Bắc Kinh - Hàng Châu, Tế Ninh là trung tâm quan trọng của văn hóa vận hà.'),
  'jining/sword': ('Các anh hùng Lương Sơn', '108 vị anh hùng hảo hán trong tác phẩm kinh điển Thủy Hử đã tụ nghĩa tại vùng đồi núi đầm lầy này.'),
  'jining/fishnet': ('Hồ Vi Sơn', 'Trên mặt hồ sen lớn nhất miền Bắc, các ngư dân vẫn duy trì phương thức đánh bắt cá truyền thống từ bao đời nay.'),
  'langfang/culture': ('Trung tâm Văn hóa Con đường Tơ lụa', 'Trung tâm văn hóa hiện đại quy mô lớn này là nơi hội tụ tinh hoa nghệ thuật dọc theo Con đường Tơ lụa.'),
  'langfang/furniture': ('Thành phố Nội thất', 'Hương Hà là một trong những trung tâm sản xuất và kinh doanh đồ nội thất lớn nhất tại Trung Quốc.'),
  'langfang/tunnel': ('Địa đạo Chiến tranh Cổ đại', 'Hệ thống địa đạo quân sự có niên đại hàng nghìn năm này từng là tuyến phòng thủ biên giới quan trọng.'),
  'langfang/themepark': ('Công viên Đệ nhất Thành', 'Đây là một công viên giải trí rộng lớn tái hiện lại khung cảnh của một tòa thành cổ, thu hút rất nhiều gia đình đến tham quan.'),
  'yancheng/salt': ('Diêm Thành', 'Tên gọi của thành phố có nghĩa là \'thành phố muối\', nơi từng là trung tâm sản xuất muối quan trọng của Trung Quốc trong nhiều thế kỷ.'),
  'yancheng/crane': ('Sếu đầu đỏ', 'Vùng đất ngập nước ven biển này là nơi trú đông lớn nhất thế giới của loài sếu đầu đỏ hoang dã.'),
  'yancheng/elk': ('Hươu Père David', 'Từng có nguy cơ tuyệt chủng trong tự nhiên, loài hươu Milu đã được nhân giống và phục hồi thành công tại các vùng đất ngập nước này.'),
  'yancheng/wetland': ('Đất ngập nước ven biển', 'Những bãi bồi ven biển được UNESCO công nhận là điểm dừng chân quan trọng trên lộ trình di cư của các loài chim trên toàn cầu.'),
  'huzhou/brush': ('Bút Hồ', 'Bút Hồ, một trong \'văn phòng tứ bảo\' của nghệ thuật thư pháp Trung Hoa, được chế tác thủ công tại chính nơi này.'),
  'huzhou/bamboo': ('Rừng trúc An Cát', 'Những rừng trúc xanh mướt trải dài vô tận không chỉ là nguồn cảm hứng cho điện ảnh mà còn giúp điều hòa không khí vô cùng mát mẻ.'),
  'huzhou/silkworm': ('Tằm tơ', 'Bờ nam hồ Thái Hồ đã trở thành trung tâm sản xuất tơ lụa từ cây dâu tằm suốt hàng nghìn năm qua.'),
  'huzhou/whitetea': ('Bạch trà An Cát', 'Với lá trà màu nhạt và hương vị ngọt thanh, bạch trà An Cát được xếp vào hàng những loại trà quý hiếm nhất Trung Quốc.'),
  'quzhou/go': ('Cờ vây', 'Gắn liền với truyền thuyết về núi Lạn Kha, thành phố này được tôn vinh là \'thánh địa của cờ vây\'.'),
  'quzhou/peaks': ('Núi Giang Lang', 'Ba cột đá khổng lồ vươn thẳng lên trời tạo nên một cảnh quan độc đáo được UNESCO công nhận.'),
  'quzhou/ponkan': ('Quýt đường Cù Châu', 'Loại quýt có lớp vỏ ngọt thanh này là món quà mùa đông đặc trưng của những ngọn đồi ôn hòa.'),
  'quzhou/cake': ('Bánh nướng Cù Châu', 'Bánh nướng mè giòn rụm được nướng trên thành lò là món ăn sáng truyền thống của người dân địa phương.'),
  'huainan/tofu': ('Cái nôi của đậu phụ', 'Được phát minh tại núi Bát Công cách đây 2.000 năm, đậu phụ từ đây đã lan tỏa ra khắp nền ẩm thực thế giới.'),
  'huainan/coalmine': ('Thành phố than đá', 'Với trữ lượng than dồi dào, Hoài Nam là một trong những trung tâm năng lượng quan trọng của miền Đông Trung Quốc.'),
  'huainan/oldtown': ('Cổ thành Thọ Huyện', 'Tường thành thời Tống được bảo tồn nguyên vẹn là một ví dụ hiếm hoi về thiết kế phòng thủ cổ đại.'),
  'huainan/classic': ('Hoài Nam Tử', 'Tác phẩm triết học kinh điển do Hoài Nam Vương Lưu An biên soạn đã được viết nên trên mảnh đất này.'),
  'jingdezhen/porcelain': ('Thủ phủ gốm sứ', 'Với lịch sử sản xuất gốm sứ hoàng gia suốt ngàn năm, thành phố này được mệnh danh là \'thủ phủ gốm sứ\' của thế giới.'),
  'jingdezhen/kiln': ('Lò gốm cổ', 'Những lò nung hình rồng đốt bằng củi vẫn tiếp tục duy trì nghệ thuật làm gốm truyền thống cho đến ngày nay.'),
  'jingdezhen/bluewhite': ('Gốm sứ thanh hoa', 'Gốm trắng với họa tiết màu xanh coban là biểu tượng nổi tiếng thế giới của thành phố này.'),
  'jingdezhen/painting': ('Tranh vẽ trên gốm', 'Những tác phẩm gốm được các nghệ nhân bậc thầy vẽ bằng cọ tỉ mỉ được trân trọng như những bức tranh nghệ thuật quý giá.'),
  'jian/jinggang': ('Núi Tỉnh Cương', 'Những ngọn núi mờ sương, nơi đặt căn cứ cách mạng đầu tiên, chính là trái tim của \'du lịch đỏ\'.'),
  'jian/torch': ('Ngọn lửa cách mạng', 'Mảnh đất khởi nguồn cho tư tưởng \'một đốm lửa nhỏ có thể đốt cháy cả cánh đồng\' là một di tích lịch sử thiêng liêng.'),
  'jian/academy': ('Học viện Bạch Lộ Châu', 'Học viện nghìn năm tuổi nằm trên một hòn đảo giữa sông Cám này đã đào tạo nên vô số bậc hiền tài thời phong kiến.'),
  'jian/pine': ('Thông Tỉnh Cương', 'Những cây thông đỏ vươn mình trong sương mù tượng trưng cho tinh thần kiên cường của vùng núi này.'),
  'nanping/wuyi': ('Dãy núi Vũ Di', 'Với những vách đá đỏ và khe núi xanh, dãy núi được UNESCO công nhận này là báu vật của cả thiên nhiên lẫn văn hóa.'),
  'nanping/rocktea': ('Trà đá Vũ Di', 'Loại trà ô long "Đại Hồng Bào" mọc trên vách đá này là một trong những loại trà đắt đỏ nhất thế giới.'),
  'nanping/bambooraft': ('Bè tre Cửu Khúc', 'Những chiếc bè tre lững lờ trôi dọc theo dòng suối Cửu Khúc uốn lượn giữa các vách đá đỏ hùng vĩ.'),
  'nanping/scholar': ('Chu Hy', 'Chu Hy, người sáng lập trường phái Tân Nho giáo, từng giảng dạy dưới chân dãy núi này.'),
  'shenzhen/skyscraper': ('Tòa nhà chọc trời', 'Sự trỗi dậy của những tòa nhà chọc trời từ một làng chài chỉ trong 40 năm chính là phép màu của công cuộc cải cách tại Trung Quốc.'),
  'shenzhen/chip': ('Thành phố công nghệ', 'Với chợ điện tử Hoa Cường Bắc và các tập đoàn công nghệ lớn, Thâm Quyến được mệnh danh là "Thung lũng Silicon của Trung Quốc".'),
  'shenzhen/miniature': ('Cửa sổ thế giới', 'Công viên chủ đề tập hợp các mô hình thu nhỏ của những danh lam thắng cảnh nổi tiếng thế giới này là một biểu tượng của thành phố.'),
  'shenzhen/mangrove': ('Vịnh Thâm Quyến', 'Vịnh biển với những hàng cây đước bao quanh là thiên đường trú ngụ của các loài chim di cư và cò trắng.'),
  'xian/terracotta': ('Đội quân đất nung', 'Hàng ngàn chiến binh đất nung canh giữ lăng mộ Tần Thủy Hoàng được mệnh danh là kỳ quan thứ tám của thế giới.'),
  'xian/citywall': ('Tường thành Tây An', 'Đây là bức tường thành thời nhà Minh được bảo tồn tốt nhất Trung Quốc, nơi du khách có thể đạp xe dạo quanh trên đỉnh thành.'),
  'xian/drumtower': ('Tháp Chuông', 'Tòa tháp chuông từ thời nhà Minh nằm ngay trung tâm chính là trái tim của cố đô xưa.'),
  'xian/roujiamo': ('Roujiamo', 'Với phần thịt tẩm gia vị kẹp trong bánh mì giòn, roujiamo được coi là phiên bản bánh burger nguyên bản của Con đường Tơ lụa.'),
  'suzhou/garden': ('Viên lâm Tô Châu', 'Được thiết kế tinh xảo với non bộ, ao hồ và đình đài, các khu vườn này đã được UNESCO công nhận là di sản thế giới.'),
  'suzhou/watertown': ('Thị trấn nước', 'Với những con kênh, cầu đá và những ngôi nhà trắng, Tô Châu được ví như "Venice của phương Đông".'),
  'suzhou/embroidery': ('Tô Tú', 'Nghệ thuật thêu lụa hai mặt là một nghề thủ công truyền thống có lịch sử hàng ngàn năm tại Tô Châu.'),
  'suzhou/kunqu': ('Côn khúc', 'Được coi là cái nôi của các loại hình hí kịch Trung Hoa, Côn khúc thanh tao đã ra đời tại chính nơi đây.'),
  'kunming/stoneforest': ('Thạch Lâm', 'Những cột đá vôi khổng lồ được thiên nhiên chạm khắc qua hàng triệu năm tạo nên một mê cung đá kỳ ảo.'),
  'kunming/springcity': ('Thành phố mùa xuân', 'Với khí hậu ôn hòa quanh năm, Côn Minh được mệnh danh là "thành phố mùa xuân" nơi hoa nở không bao giờ tàn.'),
  'kunming/seagull': ('Mòng biển đầu đen', 'Mỗi độ đông về, hàng ngàn chú mòng biển từ Siberia lại bay đến nhuộm trắng cả bờ hồ.'),
  'kunming/ricenoodle': ('Bún qua cầu', 'Món bún gạo sợi mảnh được thả vào bát nước dùng nóng hổi ngay tại bàn là đặc sản trứ danh của Vân Nam.'),
  'jinan/spring': ('Thành phố suối', 'Tế Nam được gọi là "thành phố suối" nhờ có 72 dòng suối nổi tiếng phun trào từ lòng đất.'),
  'jinan/daminglake': ('Hồ Đại Minh', 'Được bao quanh bởi những rặng liễu và hoa sen, hồ nước này được nuôi dưỡng bởi chính các dòng suối trong thành phố.'),
  'jinan/buddhamountain': ('Núi Thiên Phật', 'Với hàng trăm bức tượng Phật được chạm khắc trên sườn núi, nơi đây trở thành điểm hành hương linh thiêng.'),
  'jinan/poet': ('Nữ sĩ Lý Thanh Chiếu', 'Lý Thanh Chiếu, nữ thi sĩ vĩ đại nhất lịch sử Trung Quốc, đã sinh ra tại thành phố suối này.'),
  'ningbo/library': ('Thiên Nhất Các', 'Với lịch sử 450 năm, Thiên Nhất Các là thư viện tư nhân cổ nhất còn tồn tại ở châu Á.'),
  'ningbo/port': ('Cảng Ninh Ba - Chu Sơn', 'Cảng Ninh Ba - Chu Sơn hiện là cảng biển bận rộn nhất thế giới tính theo tổng lượng hàng hóa.'),
  'ningbo/tangyuan': ('Thang viên', 'Thang viên, món bánh trôi nhân mè đen ngọt ngào, là đặc sản mang tính biểu tượng của thành phố này.'),
  'ningbo/seafood': ('Hải sản', 'Cá đù vàng và cua từ vùng biển Hoa Đông là những nguyên liệu chủ đạo trong ẩm thực địa phương.'),
  'shijiazhuang/bridge': ('Cầu Triệu Châu', 'Cây cầu vòm đá 1.400 năm tuổi này là cây cầu vòm hở cổ nhất thế giới.'),
  'shijiazhuang/clifftemple': ('Núi Thương Nham', 'Ngôi chùa nằm vắt vẻo giữa các vách đá này từng là bối cảnh của vô số bộ phim nổi tiếng.'),
  'shijiazhuang/redbase': ('Khu di tích Tây Bách Pha', 'Ngôi làng nơi hoạch định nên nước Trung Hoa mới này là một điểm đến thiêng liêng của du lịch đỏ.'),
  'shijiazhuang/pharma': ('Thành phố Dược phẩm', 'Là một trong những trung tâm sản xuất dược phẩm lớn nhất Trung Quốc, thành phố này đóng vai trò chủ chốt trong ngành công nghiệp kháng sinh.'),
  'taiyuan/jincitemple': ('Đền Tấn Từ', 'Với những bức tượng và dòng suối có lịch sử ba nghìn năm, Tấn Từ là khu vườn đền đài duyên dáng nhất miền Bắc Trung Quốc.'),
  'taiyuan/coalcart': ('Thủ phủ than đá', 'Các mỏ than của Sơn Tây cung cấp năng lượng cho cả Trung Quốc và Thái Nguyên chính là thủ phủ của nguồn tài nguyên giàu có đó.'),
  'taiyuan/vinegar': ('Giấm lão trần', 'Giấm lão trần là loại gia vị tạo nên vị chua đặc trưng không thể thiếu trong ẩm thực Sơn Tây.'),
  'taiyuan/twinpagoda': ('Song Tháp', 'Hai ngôi chùa bát giác từ thời nhà Minh đứng sừng sững cạnh nhau đã trở thành biểu tượng của thành phố.'),
  'hohhot/lamatemple': ('Chùa Đại Chiêu', 'Nổi tiếng với tượng Phật bạc, ngôi chùa Phật giáo Tây Tạng này là trái tim tâm linh của thành phố.'),
  'hohhot/dairy': ('Thủ phủ sữa', 'Nơi đây là cái nôi của những thương hiệu sữa lớn nhất Trung Quốc, vì vậy thành phố còn được mệnh danh là \'thủ phủ sữa\'.'),
  'hohhot/wrestling': ('Đấu vật Mông Cổ', 'Đấu vật Bökh là điểm nhấn trong lễ hội Naadam, thể hiện sức mạnh của những người con vùng thảo nguyên.'),
  'hohhot/prairie': ('Thảo nguyên', 'Trải dài bên ngoài thành phố là những thảo nguyên Mông Cổ xanh mướt, nơi có những đàn ngựa và gia súc tung tăng gặm cỏ.'),
  'sanya/resortbeach': ('Bãi biển nhiệt đới', 'Với bãi cát trắng mịn và làn nước xanh ngọc, vịnh Á Long được ví như \'Hawaii của Trung Quốc\'.'),
  'sanya/guanyin': ('Tượng Quan Âm', 'Với chiều cao 108 mét vươn lên trên mặt biển, tượng Quan Âm là một trong những bức tượng nữ thần cao nhất thế giới.'),
  'sanya/diving': ('Lặn biển', 'Sở hữu làn nước ấm áp, trong vắt cùng những rạn san hô rực rỡ, Tam Á chính là thiên đường lặn biển của Trung Quốc.'),
  'sanya/coconutdrink': ('Dừa', 'Nước dừa tươi từ những rặng dừa nhiệt đới là thức uống giải khát tuyệt vời trên hòn đảo này.'),
  'yangzhou/slenderlake': ('Sấu Tây Hồ', 'Với những hàng liễu rủ và cây cầu trắng, Sấu Tây Hồ mang vẻ đẹp duyên dáng tựa như một bức tranh thủy mặc.'),
  'yangzhou/friedrice': ('Cơm chiên Dương Châu', 'Món cơm vàng óng kết hợp cùng tôm và trứng này là một đặc sản nổi tiếng thế giới.'),
  'yangzhou/morningtea': ('Trà sáng', 'Thưởng thức bữa sáng tao nhã với các loại bánh bao hấp và trà là một nét văn hóa đặc trưng của Dương Châu.'),
  'yangzhou/gegarden': ('Cá Viên', 'Khu vườn tre với những hòn non bộ mô phỏng bốn mùa này là một kiệt tác của nghệ thuật thiết kế cổ điển.'),
  'weihai/navalisland': ('Đảo Lưu Công', 'Từng là căn cứ của Hạm đội Bắc Dương, hòn đảo này là nhân chứng cho lịch sử hải quân Trung Quốc hiện đại.'),
  'weihai/swan': ('Hồ Thiên Nga', 'Mỗi độ đông về, hàng trăm chú thiên nga từ Siberia lại bay về cư ngụ tại đầm phá ven biển này.'),
  'weihai/seacucumber': ('Hải sâm', 'Được nuôi trồng trong vùng nước lạnh và sạch, hải sâm là loại hải sản quý giá nhất của thành phố này.'),
  'weihai/cape': ('Mũi đất Trung Quốc', 'Đây là mũi đất cực đông của Trung Quốc, nơi đón những tia nắng đầu tiên của ngày mới.'),
  'handan/taichi': ('Thái Cực Quyền', 'Thành cổ Quảng Phủ, nơi khai sinh ra phái Dương và phái Võ, chính là cái nôi của môn Thái Cực Quyền.'),
  'handan/congtai': ('Tùng Đài', 'Đài đất cổ từ thời nước Triệu này đã chứng kiến hơn 2.000 năm lịch sử thăng trầm.'),
  'handan/idiom': ('Thành phố thành ngữ', 'Với hơn 1.500 câu thành ngữ bắt nguồn từ đây, Hàm Đan được mệnh danh là \'thành phố thành ngữ\'.'),
  'handan/ciporcelain': ('Gốm Từ Châu', 'Gốm Từ Châu với họa tiết đen trên nền trắng là một dòng gốm dân gian kinh điển.'),
  'daqing/oilpump': ('Mỏ dầu', 'Mỏ dầu lớn nhất Trung Quốc này nổi bật với những chiếc máy bơm dầu hoạt động không ngừng nghỉ.'),
  'daqing/oilworker': ('Người sắt', 'Tinh thần kiên cường của người anh hùng công nhân dầu khí Vương Tiến Hỷ chính là linh hồn tạo nên thành phố này.'),
  'daqing/reedlake': ('Đất ngập nước', 'Những hồ lau sậy rộng lớn nằm xen kẽ giữa các giếng dầu là nơi trú ngụ của nhiều loài sếu và thiên nga.'),
  'daqing/hotspring': ('Suối nước nóng', 'Nguồn nước khoáng nóng từ lòng đất mang đến sự thư giãn tuyệt vời giữa cái lạnh của vùng phương Bắc.'),
  'zibo/bbq': ('Đồ nướng Truy Bác', 'Món thịt xiên nướng trên bếp than nhỏ rồi cuốn trong bánh tráng mỏng đã tạo nên một cơn sốt ẩm thực lan rộng khắp cả nước.'),
  'zibo/cuju': ('Xúc cúc', 'Xúc cúc, hình thức bóng đá cổ xưa nhất thế giới, từng được chơi tại Lâm Truy, kinh đô cũ của nước Tề.'),
  'zibo/ceramic': ('Gốm sứ Truy Bác', 'Với những lò nung có lịch sử hàng nghìn năm, thành phố này là trung tâm sản xuất gốm sứ nổi tiếng của miền Bắc Trung Quốc.'),
  'zibo/glass': ('Lưu ly', 'Lưu ly là một loại thủ công mỹ nghệ được làm từ thủy tinh nóng chảy, mang vẻ đẹp rực rỡ và đầy màu sắc.'),
  'taian/mounttai': ('Núi Thái Sơn', 'Đứng đầu trong Ngũ Nhạc, Thái Sơn là ngọn núi linh thiêng nhất nơi các hoàng đế xưa thường làm lễ tế trời.'),
  'taian/sunrise': ('Ngắm bình minh trên đỉnh núi', 'Chiêm ngưỡng cảnh mặt trời mọc trên biển mây là phần thưởng xứng đáng cho hành trình leo núi Thái Sơn.'),
  'taian/stonesteps': ('Đường bậc thang đá', 'Hơn 7.000 bậc thang đá dẫn lên đỉnh núi chính là thử thách thể lực đầy gian nan trên con đường hành hương.'),
  'taian/daitemple': ('Đại Miếu', 'Ngôi đền tráng lệ nằm dưới chân núi là nơi các hoàng đế chuẩn bị cho các nghi lễ tế lễ tại Thái Sơn.'),
  'lianyungang/monkey': ('Hoa Quả Sơn', 'Hoa Quả Sơn, quê hương của Tôn Ngộ Không trong tác phẩm \'Tây Du Ký\', tọa lạc ngay tại nơi đây.'),
  'lianyungang/seaport': ('Cảng biển Liên Vân Cảng', 'Đây là cửa ngõ biển phía đông của Con đường Tơ lụa và là điểm cuối phía Thái Bình Dương của cây cầu đường sắt Á-Âu.'),
  'lianyungang/mountain': ('Núi Vân Đài', 'Với những đỉnh núi dốc đứng và rừng cây xanh mướt, Vân Đài là ngọn núi cao nhất tại tỉnh Giang Tô.'),
  'lianyungang/crystal': ('Thủ phủ pha lê', 'Khu vực Đông Hải lân cận là nơi tập trung một trong những thị trường pha lê thạch anh lớn nhất thế giới.'),
  'maanshan/libai': ('Thi tiên Lý Bạch', 'Thành phố ven sông này là nơi an nghỉ cuối cùng của Lý Bạch, nhà thơ vĩ đại nhất trong lịch sử Trung Quốc.'),
  'maanshan/steel': ('Thành phố thép', 'Nhà máy thép Mã Cương đã biến nơi đây trở thành một trong những cơ sở công nghiệp gang thép trọng điểm của Trung Quốc.'),
  'maanshan/rivercliff': ('Thái Thạch Cơ', 'Vách đá hùng vĩ đổ xuống dòng Trường Giang này chính là bối cảnh thơ mộng gắn liền với những huyền thoại về thi hào Lý Bạch.'),
  'maanshan/moonwine': ('Trăng và Rượu', 'Vẻ đẹp của trăng và rượu trong thơ Lý Bạch vẫn được tôn vinh qua các lễ hội bên bờ sông.'),
  'longyan/tulou': ('Thổ lâu Vĩnh Định', 'Những pháo đài nhà ở hình tròn khổng lồ của người Khách Gia nằm rải rác trên các ngọn đồi đã được UNESCO công nhận là di sản thế giới.'),
  'longyan/redmeeting': ('Hội nghị Cổ Điền', 'Đây là nơi diễn ra hội nghị lịch sử định hình con đường phát triển của Hồng quân Trung Quốc.'),
  'longyan/hakka': ('Văn hóa Khách Gia', 'Người Khách Gia, những người di cư từ phương Bắc, vẫn lưu giữ ngôn ngữ và ẩm thực đặc trưng của mình tại vùng đồi núi này.'),
  'longyan/mountain': ('Núi Quan Trại', 'Với những vách đá đỏ và hồ nước trong vắt, ngọn núi này được coi là viên ngọc tự nhiên của vùng nam Phúc Kiến.'),
  'beijing/great-wall': ('Vạn Lý Trường Thành', 'Đây là công trình phòng thủ dài nhất thế giới với hơn 20.000 km được xây dựng qua nhiều thế kỷ, trong đó đoạn Bát Đạt Lĩnh gần Bắc Kinh là nơi thu hút nhiều du khách nhất.'),
  'beijing/temple': ('Thiên Đàn', 'Đây là nơi các hoàng đế nhà Minh và nhà Thanh từng cầu nguyện cho mùa màng bội thu, nổi tiếng với kiến trúc mái tròn ba tầng màu xanh không dùng một chiếc đinh nào.'),
  'beijing/pagoda': ('Tháp Thiên Ninh', 'Ngôi tháp gạch 13 tầng cao 57 mét từ thời nhà Liêu này là một trong những công trình cổ nhất còn sót lại, chứng nhân cho lịch sử ngàn năm của Bắc Kinh.'),
  'beijing/opera': ('Kinh kịch', 'Loại hình sân khấu truyền thống 200 năm tuổi này kết hợp giữa ca hát, đối thoại, võ thuật và nhào lộn, với các lớp hóa trang mặt nạ (liên phổ) thể hiện tính cách nhân vật.'),
};
